FUNCTION Forward-Planning-Search(problem):
 frontier = PriorityQueue with initial state
 explored = empty set
 while frontier not empty:
 state = frontier.pop()
 if Goal-Test(problem.goal, state):
 return Extract-Path(state)
 if state not in explored:
 explored.add(state)
 for each action in Applicable-Actions(state):
 nextState = Result(state, action)
 if nextState not in explored:
 frontier.push(nextState, Cost(state, action))
 return FAILURE

FUNCTION Backward-Planning-Search(problem):
 frontier = PriorityQueue with goal state
 explored = empty set
 while frontier not empty:
 state = frontier.pop()
 if state == problem.initial:
 return Extract-Path(state)
 if state not in explored:
 explored.add(state)
 for each action in Relevant-Actions(state):
 regressedState = Goal-Regress(state, action)
 if regressedState not in explored:
 frontier.push(regressedState)
 return FAILURE

FUNCTION Goal-Regress(goal, action):
 // Returns states from which action leads to goal
 return (goal - Effects(action)) ∪ Preconditions(action)

FUNCTION Partial-Order-Plan(initial, goal, actions):
 plan = Create-Plan()
 Add-Start-State(plan, initial)
 Add-Finish-State(plan, goal)
 openPreconditions = goal - Facts(Start)
 while openPreconditions not empty:
 Choose(openPreconditions, p)
 Select(Action, actions, p)
 Add-Action(plan, Action)
 Add-Causal-Link(plan, Action, p, Producer(Action, p))
 Add-Ordering-Constraint(plan, Producer(Action,p)) → Action)
 openPreconditions = openPreconditions - {p}
 for each newPrecond in Preconditions(Action):
 if not satisfied in plan:
 openPreconditions = openPreconditions ∪ {newPrecond}
 return plan

FUNCTION H-Add(state, goal):
 cost = 0
 remaining = goal - Facts(state)
 while remaining not empty:
 // Find action with cheapest add that helps remaining
 action = argmin(a in Actions(state, remaining), Cost(Add(a)))
 if no action found:
 return INFINITY
 cost = cost + Cost(action)
 remaining = remaining - Add(action)
 remaining = remaining ∪ (Preconditions(action) - Facts(state))
 return cost

// Note: Returns sum of action costs ignoring deletes
